CREATE TYPE deal_stage AS ENUM ('prospect','qualified','proposal','negotiation','won','lost');
CREATE TABLE deals (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),account_id uuid NOT NULL REFERENCES accounts(id) ON DELETE RESTRICT,name varchar(160) NOT NULL,amount numeric(14,2) NOT NULL CHECK(amount>=0),probability smallint NOT NULL CHECK(probability BETWEEN 0 AND 100),stage deal_stage NOT NULL DEFAULT 'prospect',close_date date NOT NULL,owner_id uuid NOT NULL,metadata jsonb NOT NULL DEFAULT '{}',created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());